module binary_counter_3bit(
    input clk,           // Clock signal.
    input rst,           // Synchronous reset signal.

    output [2:0] count   // 3-bit counter output.
);

reg [2:0] cnt_reg;

//------------------------------------------------
// 3-bit Binary Counter logic
always @(posedge clk) begin
    if (rst) begin
        cnt_reg <= 3'b000;
    end else begin
        cnt_reg <= cnt_reg + 1;
    end
end

assign count = cnt_reg;

endmodule
